namespace HaCreator.GUI.InstanceEditor { public partial class PortalInstanceEditor : EditorBase { public PortalInstance item; public PortalInstanceEditor(PortalInstance item) { InitializeComponent(); this.item = item; for (int i = 0; i < Program.InfoManager.PortalEditor_TypeById.Count; i++) try { ptComboBox.Items.Add(PortalTypeExtensions.GetFriendlyName(Program.InfoManager.PortalEditor_TypeById[i])); } catch (KeyNotFoundException) { } Set(xInput, item.X); Set(yInput, item.Y); pnBox.Text = item.pn; thisMap.IsChecked = item.tm == item.Board.MapInfo.id; Set(tmBox, item.tm); tnBox.Text = item.tn; scriptBox.Text = item.script ?? string.Empty; Load(item.delay, delayEnable, delayBox); Load(item.hRange, rangeEnable, hRangeBox); Load(item.vRange, rangeEnable, vRangeBox); Load(item.horizontalImpact, hImpactEnable, hImpactBox); Load(item.verticalImpact, vImpactEnable, vImpactBox); onlyOnce.IsChecked = item.onlyOnce.HasValue && item.onlyOnce.Value; hideTooltip.IsChecked = item.hideTooltip.HasValue && item.hideTooltip.Value; reactorNameBox.Text = item.reactorName ?? string.Empty; sessionKeyBox.Text = item.sessionValueKey ?? string.Empty; sessionValueBox.Text = item.sessionValue ?? string.Empty; ptComboBox.SelectedIndex = Program.InfoManager.PortalIdByType[item.pt]; ThisMap_Changed(null, null); Optional_Changed(null, null); if (item.image != null) portalImageList.SelectedItem = item.image; } private static void Set(TextBox b, int v) => InstanceEditorDialogSupport.SetInt(b, v); private static void Load(int? v, CheckBox c, TextBox b) { if (v.HasValue) { c.IsChecked = true; Set(b, v.Value); } } private static int? Opt(CheckBox c, TextBox b) => c.IsChecked == true ? InstanceEditorDialogSupport.GetInt(b) : null; protected override void cancelButton_Click(object s, EventArgs e) => Close(); protected override void okButton_Click(object s, EventArgs e) { if (ptComboBox.SelectedIndex < 0) return; lock (item.Board.ParentControl) { int x = InstanceEditorDialogSupport.GetInt(xInput, item.X), y = InstanceEditorDialogSupport.GetInt(yInput, item.Y); List<UndoRedoAction> a = new(); if (x != item.X || y != item.Y) { a.Add(UndoRedoManager.ItemMoved(item, new Microsoft.Xna.Framework.Point(item.X, item.Y), new Microsoft.Xna.Framework.Point(x, y))); item.Move(x, y); } if (a.Count > 0) item.Board.UndoRedoMan.AddUndoBatch(a); PortalType type = Program.InfoManager.PortalEditor_TypeById[ptComboBox.SelectedIndex]; item.pt = type; if (type == PortalType.StartPoint) { item.pn = "sp"; item.tm = MapConstants.MaxMap; item.tn = ""; item.script = null; item.delay = item.hRange = item.vRange = item.horizontalImpact = item.verticalImpact = null; item.onlyOnce = item.hideTooltip = null; } else { item.pn = pnBox.Text; item.tm = thisMap.IsChecked == true ? item.Board.MapInfo.id : InstanceEditorDialogSupport.GetInt(tmBox, item.tm); item.tn = tnBox.Text; item.script = scriptSection.Visibility == Visibility.Visible ? NullIfEmpty(scriptBox.Text) : null; item.delay = delaySectionVisible ? Opt(delayEnable, delayBox) : null; item.hRange = rangeSection.Visibility == Visibility.Visible ? Opt(rangeEnable, hRangeBox) : null; item.vRange = rangeSection.Visibility == Visibility.Visible ? Opt(rangeEnable, vRangeBox) : null; item.horizontalImpact = impactSection.Visibility == Visibility.Visible ? Opt(hImpactEnable, hImpactBox) : null; item.verticalImpact = impactSection.Visibility == Visibility.Visible ? Opt(vImpactEnable, vImpactBox) : null; item.onlyOnce = boolSection.Visibility == Visibility.Visible ? onlyOnce.IsChecked : null; item.hideTooltip = boolSection.Visibility == Visibility.Visible ? hideTooltip.IsChecked : null; } if (portalImageList.SelectedItem is string image) item.image = image; item.reactorName = NullIfEmpty(reactorNameBox.Text); item.sessionValueKey = NullIfEmpty(sessionKeyBox.Text); item.sessionValue = NullIfEmpty(sessionValueBox.Text); } Close(); } private bool delaySectionVisible => delayEnable.Visibility == Visibility.Visible; private static string NullIfEmpty(string v) => string.IsNullOrWhiteSpace(v) ? null : v.Trim(); private void ThisMap_Changed(object s, RoutedEventArgs e) { if (tmBox == null) return; bool same = thisMap.IsChecked == true; tmBox.IsEnabled = browseMapButton.IsEnabled = !same; browseTnButton.IsEnabled = same; } private void Optional_Changed(object s, RoutedEventArgs e) { if (delayBox == null) return; delayBox.IsEnabled = delayEnable.IsChecked == true; hRangeBox.IsEnabled = vRangeBox.IsEnabled = rangeEnable.IsChecked == true; hImpactBox.IsEnabled = hImpactEnable.IsChecked == true; vImpactBox.IsEnabled = vImpactEnable.IsChecked == true; } private void PortalType_Changed(object s, SelectionChangedEventArgs e) { if (ptComboBox.SelectedIndex < 0 || pnSection == null) return; PortalType t = Program.InfoManager.PortalEditor_TypeById[ptComboBox.SelectedIndex]; bool start = t == PortalType.StartPoint || t == PortalType.TownPortalPoint; bool script = t == PortalType.Script || t == PortalType.ScriptInvisible || t == PortalType.ScriptHidden || t == PortalType.CollisionScript || t == PortalType.ChangeableInvisible; bool range = t == PortalType.Collision || t == PortalType.CollisionScript; bool impact = t == PortalType.CollisionCustomImpact || t == PortalType.CollisionUnknownPcig; pnSection.Visibility = start ? Visibility.Collapsed : Visibility.Visible; targetSection.Visibility = start || script ? Visibility.Collapsed : Visibility.Visible; scriptSection.Visibility = script ? Visibility.Visible : Visibility.Collapsed; delayEnable.Visibility = start ? Visibility.Collapsed : Visibility.Visible; delayBox.Visibility = delayEnable.Visibility; rangeSection.Visibility = range ? Visibility.Visible : Visibility.Collapsed; impactSection.Visibility = impact ? Visibility.Visible : Visibility.Collapsed; boolSection.Visibility = start ? Visibility.Collapsed : Visibility.Visible; LoadPortalImages(t); } private void LoadPortalImages(PortalType t) { portalImageList.Items.Clear(); portalImage.Source = null; if (!Program.InfoManager.PortalGame.TryGetValue(t, out PortalGameImageInfo info)) { imageSection.Visibility = Visibility.Collapsed; return; } imageSection.Visibility = Visibility.Visible; IDictionaryEnumerator it = info.GetEnumerator(); while (it.MoveNext()) portalImageList.Items.Add((string)it.Key); if (portalImageList.Items.Count > 0) portalImageList.SelectedIndex = 0; } private void PortalImage_Changed(object s, SelectionChangedEventArgs e) { if (portalImageList.SelectedItem is not string name || ptComboBox.SelectedIndex < 0) return; PortalType t = Program.InfoManager.PortalEditor_TypeById[ptComboBox.SelectedIndex]; Bitmap bitmap = Program.InfoManager.PortalGame.ContainsKey(t) && Program.InfoManager.PortalGame[t]?[name]?.Count > 0 ? Program.InfoManager.PortalGame[t][name][0] : global::HaCreator.Properties.Resources.placeholder; portalImage.Source = SelectorDialogSupport.ToBitmapSource(bitmap); } private void BrowseMap_Click(object s, RoutedEventArgs e) { LoadMapSelector selector = new() { Owner = this }; if (selector.ShowDialog() == true) tmBox.Text = selector.SelectedMap; } private void BrowseTn_Click(object s, RoutedEventArgs e) { string target = TnSelector.Show(item.Board); if (target != null) tnBox.Text = target; } private void Cancel_Click(object s, RoutedEventArgs e) => cancelButton_Click(s, EventArgs.Empty); private void Ok_Click(object s, RoutedEventArgs e) => okButton_Click(s, EventArgs.Empty); } }
